(815, 'ARUN SINGH', '1993-08-05', 'Male', '8088243651', 'arunsinghthakur265@gmail.com', 'Plot no. 11/7 , 3rd cross Munnekolala', 'Bengalore', 'Karnataka', '560037', 'India', 'Plot no. 11/7 , 3rd cross Munnekolala', 'Bengalore', 'Karnataka', '560037', 'India', 'RBSE', '2007', '60', 'RBSE', '2010', '62', 'RTU KOTA', 'MECRC', 'BTECH', 'ECE', '2014', '64', 'English, Hindi, Punjabi', 'LT.SHREE BANGALI SINGH', 'NA', 'SUMAN SINGH', 'HOUSE WIFE', NULL, NULL, NULL, NULL, 'Arun Kumar Singh', '2026-04-23', NULL, NULL, NULL, NULL, NULL, NULL, 'PTU ', 'CDAC MOHALI', 'MTECH', 'VLSI', '2017', '7.6', '568005382979', 'IT', 'approved', '4497', NULL, NULL, NULL, NULL, 'https://drive.google.com/drive/u/1/folders/1GuX-Kf6aj97CRzg57LvAX0NKWQAelz0D', '1 Month', 'Trainee Software Engineer', NULL, 'Internship', '\r\n            Dear <b>ARUN SINGH</b>,<br><br>We are pleased to inform you that you have successfully qualified through our preliminary selection procedures and eligibility criteria. Therefore, we are pleased to offer you a provisional position as <b></b> in our organization, under the category <b>\'Journey to Corporate Talent Acquisition Initiative\'</b>. This provisional period will continue <b>1 Month</b>, until <b><span id=\"endDateSentence\">23-05-2026</span></b>.<br><br><b>Designation:</b> <b></b><br><b>Associate ID:</b> <b>4497</b><br><b>Date of Joining:</b> <b><span id=\"joinDateText\">23-04-2026</span></b><br><b>End Date of Contract:</b> <b><span id=\"endDateText\">23-05-2026</span></b><br><br>We are eager to have you as part of our team. We foresee your potential skills as a valuable contribution to our company.<br><br>You will be required to complete your assigned tasks regularly within strict scheduled time frames without any delay. Regular performance reviews will be conducted to assess your performance and suitability. You must maintain strict confidence and secrecy of the company\'s information.<br><br>If the letter is acceptable to you kindly sign and return the duplicate copy of this letter as a token of your acceptance.\r\n        ', 'Internship Joining Letter', '2026-04-27', NULL, '1SoSUEhPQKwdpo9cnjkZ6e0rf6bu3W-AY', 'PCS/JL/2026/0209', NULL, 'internship', 'Yes', 'Free', NULL, NULL, NULL, NULL, NULL),
(816, 'Surya Kanta Hazra', '1999-11-15', 'Male', '9836437283', 'suryakantahazra6@gmail.com', 'Latibpur, Uluberia, Howrah', 'Howrah', 'West Bengal', '711316', 'India', 'Latibpur, Uluberia, Howrah', 'Howrah', 'West Bengal', '711316', 'India', 'WBBSE', '2015', '91.71', 'WBCHSE', '2017', '87.20%', 'MAKAUT', 'Cooch Behar Government Engineering College', 'B Tech', 'Computer Science & Engineering ', '2021', '8.88', 'English, Hindi, Bengali', 'Sanat Kumar Hazra', 'Not Working', 'Lt. Rita Rani Hazra', 'NA', NULL, NULL, NULL, NULL, 'Surya Kanta Hazra', '2026-04-20', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '533052350855', 'IT', 'approved', '4498', NULL, NULL, NULL, NULL, NULL, NULL, 'Intern Data Analyst', NULL, 'Internship', '\r\n            Dear <b>Surya Kanta Hazra</b>,<br><br>We are pleased to inform you that you have successfully qualified through our selection process. Based on your performance and evaluation, we are delighted to offer you a <b>Paid Internship</b> opportunity with <b>PCS Global Pvt. Ltd.</b> under the initiative <b>\'Journey to Corporate Talent Acquisition\'</b>.<br><br><b>Associate ID:</b> <b>4498</b><br><b>Designation:</b> <b>Intern Data Analyst</b><br><b>Role:</b> <b>Intern Data Analyst</b><br><b>Date of Joining:</b> <b><span id=\"joinDateText\">20-04-2026</span></b><br><br>During the course of your internship, you will be assigned tasks and projects aligned with your role. You are expected to complete your responsibilities within the stipulated timelines while maintaining high standards of quality and professionalism.<br><br>Your performance will be reviewed periodically, and based on your performance, you may be considered for future opportunities within the organization.<br><br>You are required to maintain strict confidentiality of all company-related information and adhere to the policies and guidelines of PCS Global Pvt. Ltd. at all times.<br><br>Kindly acknowledge your acceptance of this offer by signing and returning a copy of this letter.<br><br>We look forward to your valuable contribution and wish you a successful and enriching experience with us.\r\n        ', 'Internship Appointment Letter', '2026-04-23', NULL, '1LwxK9KBgNnbxPLHjUAfJJqAtSUwvDJti', 'PCS/JL/2026/0204', NULL, 'internship', 'Yes', 'Paid', 'Intern Data Analyst', '', NULL, NULL, NULL),
